No, this is extremely dangerous! Client-side authorization checks can be trivially bypassed by attackers. The Parler incident in 2021 demonstrated this catastrophically - attackers bypassed frontend checks and directly accessed API endpoints, scraping 70TB of user data including deleted posts with GPS coordinates.

**VULNERABLE CODE**:

```javascript
// React component with client-side only authorization
import React, { useState, useEffect } from 'react';
import axios from 'axios';

function AdminDashboard() {
  const [users, setUsers] = useState([]);
  const [currentUser, setCurrentUser] = useState(null);

  useEffect(() => {
    // Fetch current user from localStorage - DANGEROUS!
    const user = JSON.parse(localStorage.getItem('user'));
    setCurrentUser(user);

    // Client-side admin check - EASILY BYPASSED!
    if (user && user.isAdmin) {
      fetchAllUsers();
    }
  }, []);

  const fetchAllUsers = async () => {
    // API has NO server-side auth check!
    const response = await axios.get('/api/admin/users');
    setUsers(response.data);
  };

  const deleteUser = async (userId) => {
    // Anyone can call this endpoint directly!
    await axios.delete(`/api/admin/users/${userId}`);
    fetchAllUsers();
  };

  // Client-side rendering check - trivially bypassed
  if (!currentUser?.isAdmin) {
    return <div>Access Denied</div>;
  }

  return (
    <div>
      <h1>Admin Dashboard</h1>
      {users.map(user => (
        <div key={user.id}>
          {user.email} - <button onClick={() => deleteUser(user.id)}>Delete</button>
        </div>
      ))}
    </div>
  );
}

export default AdminDashboard;
```

**Attack Payload**:
```bash
# Attacker bypasses React entirely and calls API directly
curl -X GET https://api.example.com/api/admin/users \
  -H "Cookie: session=stolen_or_normal_user_session"

# Delete any user without admin rights
curl -X DELETE https://api.example.com/api/admin/users/1 \
  -H "Cookie: session=regular_user_session"

# Or simply modify localStorage in browser console
localStorage.setItem('user', JSON.stringify({id: 1, isAdmin: true}));
```

**Why This Is Dangerous**:
- Client-side JavaScript can be modified by anyone using browser DevTools
- localStorage values can be edited to grant fake admin status
- API endpoints have no server-side authorization - anyone can call them directly
- Sequential user IDs allow enumeration of all users

**SECURE VERSION**:

```javascript
// Backend: Express.js with proper server-side authorization
const express = require('express');
const jwt = require('jsonwebtoken');
const { body, param, validationResult } = require('express-validator');

const app = express();

// Authentication middleware - validates JWT token
const authenticate = (req, res, next) => {
  const token = req.cookies.accessToken;
  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    next();
  } catch (error) {
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// Authorization middleware - checks admin role on SERVER
const requireAdmin = async (req, res, next) => {
  // CRITICAL: Fetch fresh role from database, don't trust token claims alone
  const user = await db.query('SELECT role FROM users WHERE id = $1', [req.user.id]);

  if (!user.rows[0] || user.rows[0].role !== 'admin') {
    // Log unauthorized access attempt
    console.warn(`Unauthorized admin access attempt by user ${req.user.id}`);
    return res.status(403).json({ error: 'Admin access required' });
  }

  req.userRole = user.rows[0].role;
  next();
};

// Protected admin endpoint with server-side authorization
app.get('/api/admin/users', authenticate, requireAdmin, async (req, res) => {
  try {
    const users = await db.query('SELECT id, email, created_at FROM users');
    res.json(users.rows);
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.delete('/api/admin/users/:id',
  authenticate,
  requireAdmin,
  param('id').isUUID(),  // Use UUIDs, not sequential IDs
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    // Prevent self-deletion
    if (req.params.id === req.user.id) {
      return res.status(400).json({ error: 'Cannot delete yourself' });
    }

    await db.query('DELETE FROM users WHERE id = $1', [req.params.id]);
    console.log(`User ${req.params.id} deleted by admin ${req.user.id}`);
    res.json({ success: true });
  }
);
```

**Key Security Controls**:
- **Server-side authentication**: JWT tokens validated on every request before processing
- **Server-side authorization**: Admin role verified from database, not client-provided data
- **Fresh role lookup**: Role checked from DB on each request, not cached in token
- **UUID identifiers**: Non-sequential IDs prevent enumeration attacks

Excellent question! Production systems need granular Role-Based Access Control (RBAC) with permission hierarchies, audit logging, and defense in depth. Here's a complete production pattern:

**PRODUCTION PATTERN**:

```javascript
// rbac-middleware.js - Production RBAC System
const express = require('express');
const jwt = require('jsonwebtoken');
const { createClient } = require('redis');
const winston = require('winston');

// Structured audit logger
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  defaultMeta: { service: 'authorization' },
  transports: [
    new winston.transports.File({ filename: 'audit.log' }),
    new winston.transports.Console()
  ]
});

// Permission definitions - single source of truth
const PERMISSIONS = {
  USERS_READ: 'users:read',
  USERS_WRITE: 'users:write',
  USERS_DELETE: 'users:delete',
  CONTENT_READ: 'content:read',
  CONTENT_MODERATE: 'content:moderate',
  SETTINGS_ADMIN: 'settings:admin'
};

// Role-to-permission mapping
const ROLE_PERMISSIONS = {
  viewer: [
    PERMISSIONS.USERS_READ,
    PERMISSIONS.CONTENT_READ
  ],
  moderator: [
    PERMISSIONS.USERS_READ,
    PERMISSIONS.CONTENT_READ,
    PERMISSIONS.CONTENT_MODERATE
  ],
  admin: [
    PERMISSIONS.USERS_READ,
    PERMISSIONS.USERS_WRITE,
    PERMISSIONS.USERS_DELETE,
    PERMISSIONS.CONTENT_READ,
    PERMISSIONS.CONTENT_MODERATE,
    PERMISSIONS.SETTINGS_ADMIN
  ]
};

// Redis client for caching and rate limiting
const redis = createClient({ url: process.env.REDIS_URL });
redis.connect();

// Authentication middleware with token validation
const authenticate = async (req, res, next) => {
  const token = req.cookies.accessToken || req.headers.authorization?.split(' ')[1];

  if (!token) {
    auditLogger.warn({ event: 'auth_missing_token', ip: req.ip });
    return res.status(401).json({ error: 'Authentication required' });
  }

  // Check if token is blacklisted (logout/revocation)
  const isBlacklisted = await redis.get(`blacklist:${token}`);
  if (isBlacklisted) {
    auditLogger.warn({ event: 'auth_blacklisted_token', ip: req.ip });
    return res.status(401).json({ error: 'Token revoked' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET, {
      algorithms: ['HS256'],
      issuer: 'your-app',
      audience: 'your-app-users'
    });

    req.user = decoded;
    req.token = token;
    next();
  } catch (error) {
    auditLogger.warn({ event: 'auth_invalid_token', ip: req.ip, error: error.message });
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// Permission check with database verification
const requirePermission = (...requiredPermissions) => {
  return async (req, res, next) => {
    const userId = req.user.id;

    try {
      // Check cache first for performance
      let userPermissions = await redis.get(`permissions:${userId}`);

      if (!userPermissions) {
        // Fetch fresh from database
        const result = await db.query(
          `SELECT r.name as role, r.permissions 
           FROM users u 
           JOIN roles r ON u.role_id = r.id 
           WHERE u.id = $1 AND u.is_active = true`,
          [userId]
        );

        if (!result.rows[0]) {
          auditLogger.warn({
            event: 'authz_user_not_found',
            userId,
            ip: req.ip
          });
          return res.status(403).json({ error: 'Access denied' });
        }

        userPermissions = result.rows[0].permissions;

        // Cache for 5 minutes
        await redis.setEx(`permissions:${userId}`, 300, JSON.stringify(userPermissions));
      } else {
        userPermissions = JSON.parse(userPermissions);
      }

      // Check if user has ALL required permissions
      const hasPermission = requiredPermissions.every(
        perm => userPermissions.includes(perm)
      );

      if (!hasPermission) {
        auditLogger.warn({
          event: 'authz_denied',
          userId,
          required: requiredPermissions,
          actual: userPermissions,
          path: req.path,
          method: req.method,
          ip: req.ip
        });
        return res.status(403).json({ error: 'Insufficient permissions' });
      }

      // Log successful authorization for sensitive operations
      if (requiredPermissions.some(p => p.includes('delete') || p.includes('admin'))) {
        auditLogger.info({
          event: 'authz_granted_sensitive',
          userId,
          permissions: requiredPermissions,
          path: req.path,
          method: req.method,
          ip: req.ip
        });
      }

      req.userPermissions = userPermissions;
      next();
    } catch (error) {
      auditLogger.error({ event: 'authz_error', userId, error: error.message });
      return res.status(500).json({ error: 'Authorization check failed' });
    }
  };
};

// Resource-level authorization (check ownership)
const requireOwnershipOrPermission = (resourceType, permission) => {
  return async (req, res, next) => {
    const userId = req.user.id;
    const resourceId = req.params.id;

    // Admins with permission can access any resource
    if (req.userPermissions?.includes(permission)) {
      return next();
    }

    // Check resource ownership
    const result = await db.query(
      `SELECT owner_id FROM ${resourceType} WHERE id = $1`,
      [resourceId]
    );

    if (!result.rows[0] || result.rows[0].owner_id !== userId) {
      auditLogger.warn({
        event: 'authz_ownership_denied',
        userId,
        resourceType,
        resourceId,
        ip: req.ip
      });
      return res.status(403).json({ error: 'Access denied' });
    }

    next();
  };
};

// Example protected routes
const app = express();

// Rate limiting for sensitive endpoints
const rateLimit = require('express-rate-limit');
const adminLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many requests' }
});

// View users - requires USERS_READ permission
app.get('/api/users',
  authenticate,
  requirePermission(PERMISSIONS.USERS_READ),
  async (req, res) => {
    const users = await db.query('SELECT id, email, role FROM users');
    res.json(users.rows);
  }
);

// Delete user - requires USERS_DELETE permission + rate limiting
app.delete('/api/users/:id',
  adminLimiter,
  authenticate,
  requirePermission(PERMISSIONS.USERS_DELETE),
  async (req, res) => {
    // Prevent self-deletion
    if (req.params.id === req.user.id) {
      return res.status(400).json({ error: 'Cannot delete yourself' });
    }

    await db.query('UPDATE users SET is_active = false WHERE id = $1', [req.params.id]);

    // Invalidate user's permission cache
    await redis.del(`permissions:${req.params.id}`);

    auditLogger.info({
      event: 'user_deleted',
      deletedUserId: req.params.id,
      deletedBy: req.user.id,
      ip: req.ip
    });

    res.json({ success: true });
  }
);

module.exports = { authenticate, requirePermission, requireOwnershipOrPermission, PERMISSIONS };
```

**Defense in Depth Layers**:

1. **Layer 1 - Authentication**: Every request validates JWT token with proper algorithm restrictions, issuer/audience claims, and checks against a blacklist for revoked tokens.

2. **Layer 2 - Permission-Based Authorization**: Fine-grained permissions checked against database with Redis caching. Role changes take effect within cache TTL (5 minutes) or immediately on cache invalidation.

3. **Layer 3 - Resource-Level Authorization**: For user-owned resources, verify ownership OR elevated permissions. Prevents horizontal privilege escalation.

**Additional Protections**:
- **Audit logging**: All authorization decisions logged with user ID, IP, path, and timestamp for forensic analysis
- **Rate limiting**: Sensitive admin endpoints rate-limited to prevent brute force and enumeration
- **Soft deletes**: Users marked inactive rather than deleted, preserving audit trail
- **Cache invalidation**: Permission cache cleared on role changes to prevent stale authorization
- **Token revocation**: Blacklist mechanism for immediate session termination on logout or compromise
- **Fail-closed design**: Any error in authorization check results in access denied, never access granted

**Absolutely not!** Hiding UI elements with JavaScript provides zero security. Client-side authorization is one of the most dangerous access control flaws because any user can bypass it by directly calling your APIs or modifying requests.

**VULNERABLE CODE**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import javax.servlet.http.HttpSession;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class AdminController {

    private final UserRepository userRepository;
    private final AuditLogRepository auditLogRepository;

    public AdminController(UserRepository userRepository, AuditLogRepository auditLogRepository) {
        this.userRepository = userRepository;
        this.auditLogRepository = auditLogRepository;
    }

    // VULNERABLE: No server-side authorization check!
    // Relies on frontend hiding the button for non-admins
    @GetMapping("/admin/users")
    public ResponseEntity<List<User>> getAllUsers() {
        // Anyone can call this endpoint directly
        List<User> users = userRepository.findAll();
        return ResponseEntity.ok(users);
    }

    // VULNERABLE: Role passed from client-side
    @DeleteMapping("/admin/users/{userId}")
    public ResponseEntity<Void> deleteUser(
            @PathVariable Long userId,
            @RequestHeader("X-User-Role") String role) {
        // Trusting client-provided role header!
        if ("ADMIN".equals(role)) {
            userRepository.deleteById(userId);
            return ResponseEntity.ok().build();
        }
        return ResponseEntity.status(403).build();
    }

    // VULNERABLE: isAdmin flag from session can be manipulated
    @PostMapping("/admin/config")
    public ResponseEntity<Void> updateConfig(
            @RequestBody Map<String, String> config,
            HttpSession session) {
        // Session attribute set by JavaScript localStorage sync
        Boolean isAdmin = (Boolean) session.getAttribute("isAdmin");
        if (Boolean.TRUE.equals(isAdmin)) {
            configService.updateAll(config);
            return ResponseEntity.ok().build();
        }
        return ResponseEntity.status(403).build();
    }
}
```

**Attack Payload**:
```bash
# Direct API call bypassing hidden UI
curl -X GET "https://app.example.com/api/admin/users" \
  -H "Authorization: Bearer <any_valid_user_token>"

# Spoofing role header to delete any user
curl -X DELETE "https://app.example.com/api/admin/users/1" \
  -H "Authorization: Bearer <regular_user_token>" \
  -H "X-User-Role: ADMIN"

# Mass enumeration of all user data
for i in {1..10000}; do
  curl -s "https://app.example.com/api/admin/users/$i"
done
```

**Why This Is Dangerous**:
- Any authenticated user can call admin endpoints directly with curl/Postman
- Client-provided role headers can be trivially spoofed
- Hiding buttons with CSS/JavaScript is not a security control
- Attackers can enumerate all users, delete accounts, or modify configurations
- This exact pattern caused the Parler breach where 70TB of data was exposed

**SECURE VERSION**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.core.userdetails.UserDetails;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/admin")
public class SecureAdminController {

    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    private final UserRepository userRepository;
    private final UserService userService;
    private final ConfigService configService;

    public SecureAdminController(UserRepository userRepository, 
                                  UserService userService,
                                  ConfigService configService) {
        this.userRepository = userRepository;
        this.userService = userService;
        this.configService = configService;
    }

    // SECURE: Server-side role verification via Spring Security
    @GetMapping("/users")
    @PreAuthorize("hasRole('ADMIN')")
    public ResponseEntity<List<UserDTO>> getAllUsers(
            @AuthenticationPrincipal UserDetails currentUser) {

        auditLogger.info("Admin user list accessed by: {}", currentUser.getUsername());

        // Return DTOs without sensitive fields like passwords
        List<UserDTO> users = userService.getAllUsersAsDTO();
        return ResponseEntity.ok(users);
    }

    // SECURE: Role verified from authenticated principal, not request
    @DeleteMapping("/users/{userId}")
    @PreAuthorize("hasRole('ADMIN')")
    public ResponseEntity<Void> deleteUser(
            @PathVariable Long userId,
            @AuthenticationPrincipal UserDetails currentUser) {

        // Prevent self-deletion
        User targetUser = userRepository.findById(userId)
            .orElseThrow(() -> new ResourceNotFoundException("User not found"));

        if (targetUser.getUsername().equals(currentUser.getUsername())) {
            auditLogger.warn("Admin {} attempted self-deletion", currentUser.getUsername());
            return ResponseEntity.badRequest().build();
        }

        auditLogger.info("User {} deleted by admin: {}", userId, currentUser.getUsername());
        userRepository.deleteById(userId);
        return ResponseEntity.ok().build();
    }

    // SECURE: Multi-level authorization check
    @PostMapping("/config")
    @PreAuthorize("hasRole('SUPER_ADMIN')")
    public ResponseEntity<Void> updateConfig(
            @RequestBody @Valid ConfigUpdateRequest config,
            @AuthenticationPrincipal UserDetails currentUser) {

        auditLogger.info("Config update by super admin: {} - keys: {}", 
            currentUser.getUsername(), config.getKeys());

        configService.updateAll(config);
        return ResponseEntity.ok().build();
    }
}
```

**Key Security Controls**:
- **@PreAuthorize annotation**: Enforces role checks at method level before any code executes
- **@AuthenticationPrincipal**: Retrieves user identity from server-side security context, not from request
- **Audit logging**: All admin actions are logged with actor identity for forensics
- **DTO pattern**: Prevents leaking sensitive fields like password hashes

For complex authorization rules like resource-level permissions and hierarchical access, you need Attribute-Based Access Control (ABAC) or a policy engine. Simple role checks aren't sufficient.

**PRODUCTION PATTERN**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.stereotype.Service;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

// Custom security expression for complex authorization
@Service("authz")
public class AuthorizationService {

    private static final Logger auditLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    private final UserRepository userRepository;
    private final DepartmentRepository departmentRepository;
    private final ResourceShareRepository shareRepository;

    public AuthorizationService(UserRepository userRepository,
                                 DepartmentRepository departmentRepository,
                                 ResourceShareRepository shareRepository) {
        this.userRepository = userRepository;
        this.departmentRepository = departmentRepository;
        this.shareRepository = shareRepository;
    }

    /**
     * Check if current user can access the target user's data.
     * Rules:
     * 1. Users can always access their own data
     * 2. Managers can access data of users in their department
     * 3. Admins can access any user data
     * 4. Users with explicit share grants can access shared data
     */
    public boolean canAccessUser(CustomUserDetails currentUser, Long targetUserId) {
        // Rule 1: Self-access always allowed
        if (currentUser.getId().equals(targetUserId)) {
            auditLogger.debug("Self-access granted for user {}", currentUser.getId());
            return true;
        }

        // Rule 2: Admin bypass
        if (currentUser.hasRole("ADMIN")) {
            auditLogger.info("Admin access to user {} by admin {}", 
                targetUserId, currentUser.getUsername());
            return true;
        }

        User targetUser = userRepository.findById(targetUserId).orElse(null);
        if (targetUser == null) {
            auditLogger.warn("Access attempt to non-existent user {} by {}", 
                targetUserId, currentUser.getUsername());
            return false;
        }

        // Rule 3: Manager can access users in their department
        if (currentUser.hasRole("MANAGER")) {
            Set<Long> managedDepartments = departmentRepository
                .findDepartmentIdsByManagerId(currentUser.getId());

            if (managedDepartments.contains(targetUser.getDepartmentId())) {
                auditLogger.info("Manager {} accessed subordinate {} in dept {}",
                    currentUser.getUsername(), targetUserId, targetUser.getDepartmentId());
                return true;
            }
        }

        // Rule 4: Explicit share grants
        boolean hasShareGrant = shareRepository.existsByGranteeIdAndResourceTypeAndResourceId(
            currentUser.getId(), ResourceType.USER_PROFILE, targetUserId);

        if (hasShareGrant) {
            auditLogger.info("Share-based access to user {} by {}",
                targetUserId, currentUser.getUsername());
            return true;
        }

        auditLogger.warn("DENIED: User {} attempted unauthorized access to user {}",
            currentUser.getUsername(), targetUserId);
        return false;
    }

    /**
     * Get all user IDs the current user is authorized to access
     */
    public Set<Long> getAccessibleUserIds(CustomUserDetails currentUser) {
        Set<Long> accessibleIds = new java.util.HashSet<>();

        // Always include self
        accessibleIds.add(currentUser.getId());

        // Admins: return indicator for all access
        if (currentUser.hasRole("ADMIN")) {
            return null; // null signals "all access" to calling code
        }

        // Managers: add all users in managed departments
        if (currentUser.hasRole("MANAGER")) {
            Set<Long> managedDepts = departmentRepository
                .findDepartmentIdsByManagerId(currentUser.getId());

            List<Long> subordinateIds = userRepository
                .findUserIdsByDepartmentIdIn(managedDepts);
            accessibleIds.addAll(subordinateIds);
        }

        // Add explicitly shared resources
        List<Long> sharedUserIds = shareRepository
            .findResourceIdsByGranteeIdAndResourceType(
                currentUser.getId(), ResourceType.USER_PROFILE);
        accessibleIds.addAll(sharedUserIds);

        return accessibleIds;
    }
}

// Controller using the authorization service
@RestController
@RequestMapping("/api/users")
public class UserController {

    private static final Logger auditLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    private final UserService userService;
    private final AuthorizationService authzService;

    public UserController(UserService userService, AuthorizationService authzService) {
        this.userService = userService;
        this.authzService = authzService;
    }

    // Using SpEL to call custom authorization service
    @GetMapping("/{userId}")
    @PreAuthorize("@authz.canAccessUser(authentication.principal, #userId)")
    public ResponseEntity<UserDTO> getUser(
            @PathVariable Long userId,
            @AuthenticationPrincipal CustomUserDetails currentUser) {

        UserDTO user = userService.getUserDTO(userId);
        return ResponseEntity.ok(user);
    }

    // List endpoint with row-level security
    @GetMapping
    @PreAuthorize("isAuthenticated()")
    public ResponseEntity<List<UserDTO>> listUsers(
            @AuthenticationPrincipal CustomUserDetails currentUser,
            @RequestParam(defaultValue = "0") int page,
            @RequestParam(defaultValue = "20") int size) {

        Set<Long> accessibleIds = authzService.getAccessibleUserIds(currentUser);

        List<UserDTO> users;
        if (accessibleIds == null) {
            // Admin: can see all
            users = userService.getAllUserDTOs(page, size);
        } else {
            // Filter to only accessible users
            users = userService.getUserDTOsByIds(accessibleIds, page, size);
        }

        auditLogger.info("User {} listed {} users (page {})",
            currentUser.getUsername(), users.size(), page);

        return ResponseEntity.ok(users);
    }

    // Update with ownership/delegation check
    @PutMapping("/{userId}")
    @PreAuthorize("@authz.canAccessUser(authentication.principal, #userId)")
    public ResponseEntity<UserDTO> updateUser(
            @PathVariable Long userId,
            @RequestBody @Valid UserUpdateRequest request,
            @AuthenticationPrincipal CustomUserDetails currentUser) {

        // Additional check: only admins can change roles
        if (request.getRoles() != null && !currentUser.hasRole("ADMIN")) {
            auditLogger.warn("Non-admin {} attempted role change for user {}",
                currentUser.getUsername(), userId);
            throw new AccessDeniedException("Only admins can modify roles");
        }

        UserDTO updated = userService.updateUser(userId, request);

        auditLogger.info("User {} updated by {}", userId, currentUser.getUsername());
        return ResponseEntity.ok(updated);
    }
}

// Security configuration with method security enabled
@Configuration
@EnableWebSecurity
@EnableGlobalMethodSecurity(prePostEnabled = true)
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            .authorizeRequests()
                // All /api/** requires authentication - defense in depth
                .antMatchers("/api/**").authenticated()
                .anyRequest().permitAll()
            .and()
            .sessionManagement()
                .sessionCreationPolicy(SessionCreationPolicy.STATELESS)
            .and()
            .oauth2ResourceServer()
                .jwt()
                .jwtAuthenticationConverter(jwtAuthConverter());
    }

    @Bean
    public JwtAuthenticationConverter jwtAuthConverter() {
        JwtGrantedAuthoritiesConverter converter = new JwtGrantedAuthoritiesConverter();
        converter.setAuthorityPrefix("ROLE_");
        converter.setAuthoritiesClaimName("roles");

        JwtAuthenticationConverter jwtConverter = new JwtAuthenticationConverter();
        jwtConverter.setJwtGrantedAuthoritiesConverter(converter);
        return jwtConverter;
    }
}
```

**Defense in Depth Layers**:

1. **URL-Level Security** (first barrier):
```java
.antMatchers("/api/admin/**").hasRole("ADMIN")
.antMatchers("/api/**").authenticated()
```

2. **Method-Level Security** (second barrier):
```java
@PreAuthorize("@authz.canAccessUser(principal, #userId)")
public ResponseEntity<UserDTO> getUser(@PathVariable Long userId)
```

3. **Data-Level Security** (third barrier - query filtering):
```java
@Query("SELECT u FROM User u WHERE u.id IN :accessibleIds")
List<User> findByIdIn(@Param("accessibleIds") Set<Long> ids);
```

**Additional Protections**:

- **Rate limiting on sensitive endpoints**: Prevents enumeration attacks even if authorization is bypassed
```java
@RateLimiter(name = "adminEndpoints", fallbackMethod = "rateLimitFallback")
@GetMapping("/admin/users")
public ResponseEntity<List<UserDTO>> getAllUsers() { ... }
```

- **Anomaly detection**: Alert on unusual access patterns
```java
if (accessCount > THRESHOLD_PER_HOUR) {
    securityAlertService.raiseAlert(
        AlertType.POTENTIAL_ENUMERATION,
        currentUser.getId(),
        "Accessed " + accessCount + " user profiles in 1 hour"
    );
}
```

- **Immutable audit trail**: Every authorization decision is logged with tamper-evident storage
```java
auditLogger.info("action=ACCESS_CHECK user={} target={} resource={} decision={} reason={}",
    currentUser.getId(), targetUserId, "USER_PROFILE", 
    decision ? "GRANTED" : "DENIED", reason);
```

- **Authorization cache with short TTL**: Performance optimization that doesn't compromise security
```java
@Cacheable(value = "authzDecisions", key = "#userId + '-' + #targetId", 
           unless = "#result == false", ttl = 60)
public boolean canAccessUser(Long userId, Long targetId) { ... }
```

- **Fail-closed default**: If authorization service is unavailable, deny access
```java
try {
    return authzService.canAccessUser(currentUser, targetId);
} catch (Exception e) {
    auditLogger.error("Authorization service error, denying access", e);
    return false; // Fail closed
}
```

