	vars := mux.Vars(r)
	userID, _ := strconv.Atoi(vars["id"])

	// Frontend is supposed to check is_admin before allowing this call
	// But there's NO server-side verification!
	delete(users, userID)

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "user deleted"})
}

// Returns is_admin flag - frontend uses this for UI decisions
func getCurrentUser(w http.ResponseWriter, r *http.Request) {
	// Assume user ID 2 is logged in (non-admin)
	user := users[2]
	json.NewEncoder(w).Encode(user)
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/api/user", getCurrentUser).Methods("GET")
	r.HandleFunc("/api/admin/users/{id}", deleteUser).Methods("DELETE")
	http.ListenAndServe(":8080", r)
