Excellent question! Multi-tenant authorization with feature flags is where client-side authorization failures become catastrophic. You need a robust server-side policy engine that enforces tenant isolation, role-based access, and feature entitlements.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gorilla/mux"
)

// Context keys for request-scoped data
type contextKey string

const (
	tenantContextKey contextKey = "tenant"
	userContextKey   contextKey = "user"
)

// Tenant represents an organization with specific feature entitlements
type Tenant struct {
	ID           string              `json:"id"`
	Name         string              `json:"name"`
	Plan         string              `json:"plan"` // "free", "pro", "enterprise"
	Features     map[string]bool     `json:"-"`    // NEVER expose to client
	ResourceLimits map[string]int    `json:"-"`
}

// User represents a user within a tenant
type User struct {
	ID       string   `json:"id"`
	TenantID string   `json:"tenant_id"`
	Email    string   `json:"email"`
	Roles    []string `json:"-"` // NEVER expose to client
}

// Permission represents a specific action on a resource
type Permission struct {
	Resource string
	Action   string
}

// PolicyEngine - central server-side authorization
type PolicyEngine struct {
	mu              sync.RWMutex
	rolePermissions map[string][]Permission
	planFeatures    map[string]map[string]bool
	planLimits      map[string]map[string]int
}

func NewPolicyEngine() *PolicyEngine {
	return &PolicyEngine{
		rolePermissions: map[string][]Permission{
			"viewer": {
				{Resource: "reports", Action: "read"},
			},
			"editor": {
				{Resource: "reports", Action: "read"},
				{Resource: "reports", Action: "write"},
				{Resource: "data", Action: "read"},
			},
			"admin": {
				{Resource: "reports", Action: "read"},
				{Resource: "reports", Action: "write"},
				{Resource: "reports", Action: "delete"},
				{Resource: "data", Action: "read"},
				{Resource: "data", Action: "write"},
				{Resource: "users", Action: "manage"},
				{Resource: "billing", Action: "manage"},
			},
		},
		planFeatures: map[string]map[string]bool{
			"free":       {"basic_reports": true, "api_access": false, "sso": false},
			"pro":        {"basic_reports": true, "advanced_reports": true, "api_access": true, "sso": false},
			"enterprise": {"basic_reports": true, "advanced_reports": true, "api_access": true, "sso": true, "audit_logs": true},
		},
		planLimits: map[string]map[string]int{
			"free":       {"users": 5, "api_calls_per_day": 100},
			"pro":        {"users": 50, "api_calls_per_day": 10000},
			"enterprise": {"users": -1, "api_calls_per_day": -1}, // -1 = unlimited
		},
	}
}

// CheckPermission - SERVER-SIDE permission check
func (pe *PolicyEngine) CheckPermission(user User, resource, action string) bool {
	pe.mu.RLock()
	defer pe.mu.RUnlock()

	for _, role := range user.Roles {
		if perms, ok := pe.rolePermissions[role]; ok {
			for _, p := range perms {
				if p.Resource == resource && p.Action == action {
					return true
				}
			}
		}
	}
	return false
}

// CheckFeature - SERVER-SIDE feature flag check
func (pe *PolicyEngine) CheckFeature(tenant Tenant, feature string) bool {
	pe.mu.RLock()
	defer pe.mu.RUnlock()

	if features, ok := pe.planFeatures[tenant.Plan]; ok {
		return features[feature]
	}
	return false
}

// CheckResourceLimit - SERVER-SIDE resource limit check
func (pe *PolicyEngine) CheckResourceLimit(tenant Tenant, resource string, currentUsage int) bool {
	pe.mu.RLock()
	defer pe.mu.RUnlock()

	if limits, ok := pe.planLimits[tenant.Plan]; ok {
		if limit, ok := limits[resource]; ok {
			return limit == -1 || currentUsage < limit
		}
	}
	return false
}

// AuthorizationResult for audit logging
type AuthorizationResult struct {
	Allowed   bool
	Reason    string
	Timestamp time.Time
	UserID    string
	TenantID  string
	Resource  string
	Action    string
	ClientIP  string
}

// AuditLogger for security monitoring
type AuditLogger struct {
	logChan chan AuthorizationResult
}

func NewAuditLogger() *AuditLogger {
	al := &AuditLogger{logChan: make(chan AuthorizationResult, 1000)}
	go al.processLogs()
	return al
}

func (al *AuditLogger) Log(result AuthorizationResult) {
	select {
	case al.logChan <- result:
	default:
		log.Printf("ALERT: Audit log buffer full, dropping entry")
	}
}

func (al *AuditLogger) processLogs() {
	for result := range al.logChan {
		// In production: send to SIEM, CloudWatch, Splunk, etc.
		logLevel := "INFO"
		if !result.Allowed {
			logLevel = "SECURITY"
		}
		log.Printf("[%s] tenant=%s user=%s resource=%s action=%s allowed=%v reason=%s ip=%s",
			logLevel, result.TenantID, result.UserID, result.Resource,
			result.Action, result.Allowed, result.Reason, result.ClientIP)
	}
}

var (
	policyEngine *PolicyEngine
	auditLogger  *AuditLogger
)

// AuthMiddleware - validates authentication and loads tenant context
func AuthMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// In production: validate JWT, extract claims
		user, tenant, err := validateAndLoadContext(r)
		if err != nil {
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		ctx := context.WithValue(r.Context(), userContextKey, user)
		ctx = context.WithValue(ctx, tenantContextKey, tenant)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// RequirePermission - SERVER-SIDE authorization enforcement
func RequirePermission(resource, action string) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			user := r.Context().Value(userContextKey).(User)
			tenant := r.Context().Value(tenantContextKey).(Tenant)

			result := AuthorizationResult{
				Timestamp: time.Now(),
				UserID:    user.ID,
				TenantID:  tenant.ID,
				Resource:  resource,
				Action:    action,
				ClientIP:  r.RemoteAddr,
			}

			if !policyEngine.CheckPermission(user, resource, action) {
				result.Allowed = false
				result.Reason = "insufficient_role_permissions"
				auditLogger.Log(result)
				http.Error(w, "Forbidden", http.StatusForbidden)
				return
			}

			result.Allowed = true
			result.Reason = "authorized"
			auditLogger.Log(result)
			next.ServeHTTP(w, r)
		})
	}
}

// RequireFeature - SERVER-SIDE feature flag enforcement
func RequireFeature(feature string) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			user := r.Context().Value(userContextKey).(User)
			tenant := r.Context().Value(tenantContextKey).(Tenant)

			if !policyEngine.CheckFeature(tenant, feature) {
				auditLogger.Log(AuthorizationResult{
					Allowed:   false,
					Reason:    fmt.Sprintf("feature_%s_not_enabled", feature),
					Timestamp: time.Now(),
					UserID:    user.ID,
					TenantID:  tenant.ID,
					Resource:  feature,
					Action:    "access",
					ClientIP:  r.RemoteAddr,
				})

				w.Header().Set("Content-Type", "application/json")
				w.WriteHeader(http.StatusPaymentRequired)
				json.NewEncoder(w).Encode(map[string]string{
					"error":   "feature_not_available",
					"message": "Upgrade your plan to access this feature",
				})
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

// TenantIsolation - CRITICAL: Ensures users can only access their own tenant's data
func TenantIsolation(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		user := r.Context().Value(userContextKey).(User)
		requestTenantID := mux.Vars(r)["tenant_id"]

		// CRITICAL: Server-side tenant isolation
		if requestTenantID != "" && requestTenantID != user.TenantID {
			auditLogger.Log(AuthorizationResult{
				Allowed:   false,
				Reason:    "cross_tenant_access_attempt",
				Timestamp: time.Now(),
				UserID:    user.ID,
				TenantID:  user.TenantID,
				Resource:  "tenant:" + requestTenantID,
				Action:    "access",
				ClientIP:  r.RemoteAddr,
			})

			// SECURITY: Return 404, not 403, to prevent tenant enumeration
			http.Error(w, "Not Found", http.StatusNotFound)
			return
		}

		next.ServeHTTP(w, r)
	})
}

// Example protected endpoint
func getAdvancedReports(w http.ResponseWriter, r *http.Request) {
	tenant := r.Context().Value(tenantContextKey).(Tenant)
	user := r.Context().Value(userContextKey).(User)

