```php
<?php
// admin_panel.php - SECURE: Server-side authorization
session_start();

class AuthorizationService {
    private $pdo;

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
    }

    public function getCurrentUser(): ?array {
        if (!isset($_SESSION['user_id'])) {
            return null;
        }

        $stmt = $this->pdo->prepare(
            "SELECT id, username, role, permissions FROM users WHERE id = ?"
        );
        $stmt->execute([$_SESSION['user_id']]);
        return $stmt->fetch(PDO::FETCH_ASSOC) ?: null;
    }

    public function requireRole(string $requiredRole): array {
        $user = $this->getCurrentUser();

        if (!$user) {
            http_response_code(401);
            header('Location: /login.php');
            exit('Unauthorized: Please log in');
        }

        if ($user['role'] !== $requiredRole) {
            // Log unauthorized access attempt
            error_log(sprintf(
                "SECURITY: Unauthorized access attempt by user %d to %s endpoint",
                $user['id'],
                $_SERVER['REQUEST_URI']
            ));

            http_response_code(403);
            exit('Forbidden: Insufficient permissions');
        }

        return $user;
    }

    public function hasPermission(array $user, string $permission): bool {
        $permissions = json_decode($user['permissions'] ?? '[]', true);
        return in_array($permission, $permissions, true);
    }
}

class SecureAdminController {
    private $pdo;
    private $authService;

    public function __construct(PDO $pdo, AuthorizationService $authService) {
        $this->pdo = $pdo;
        $this->authService = $authService;
    }

    public function renderDashboard(): void {
        // SERVER-SIDE authorization check BEFORE rendering
        $user = $this->authService->requireRole('admin');

        // Only admins reach this point
        include 'templates/admin_dashboard.php';
    }

    public function deleteUser(): void {
        // Verify admin role on EVERY action
        $admin = $this->authService->requireRole('admin');

        // Verify specific permission
        if (!$this->authService->hasPermission($admin, 'user:delete')) {
            http_response_code(403);
            exit(json_encode(['error' => 'Missing user:delete permission']));
        }

        $userId = filter_input(INPUT_POST, 'user_id', FILTER_VALIDATE_INT);
        if (!$userId || $userId <= 0) {
            http_response_code(400);
            exit(json_encode(['error' => 'Invalid user ID']));
        }

        // Prevent self-deletion
        if ($userId === $admin['id']) {
            http_response_code(400);
            exit(json_encode(['error' => 'Cannot delete your own account']));
        }

        $stmt = $this->pdo->prepare("DELETE FROM users WHERE id = ?");
        $stmt->execute([$userId]);

        // Audit log
        error_log(sprintf(
            "AUDIT: Admin %d deleted user %d",
            $admin['id'],
            $userId
        ));

        echo json_encode(['success' => true]);
    }
}
```

**Key Security Controls**:
- **Server-side role verification**: `requireRole()` checks role in database before any action
- **Permission-based access control**: Fine-grained permissions beyond just roles
- **Conditional rendering**: Admin HTML is never sent to non-admin users
- **Input validation**: User IDs validated as positive integers
- **Audit logging**: All admin actions logged with actor identity

For hierarchical roles with varying permissions, you need a Role-Based Access Control (RBAC) or Attribute-Based Access Control (ABAC) system. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```php
<?php
// src/Security/Authorization/RBACService.php
declare(strict_types=1);

namespace App\Security\Authorization;

use PDO;
use Psr\Log\LoggerInterface;

class Permission {
    public const USER_VIEW = 'user:view';
    public const USER_CREATE = 'user:create';
    public const USER_EDIT = 'user:edit';
    public const USER_DELETE = 'user:delete';
    public const CONTENT_MODERATE = 'content:moderate';
    public const CONTENT_DELETE = 'content:delete';
    public const SETTINGS_VIEW = 'settings:view';
    public const SETTINGS_EDIT = 'settings:edit';
    public const AUDIT_VIEW = 'audit:view';
    public const ROLE_MANAGE = 'role:manage';
}

class Role {
    public const SUPER_ADMIN = 'super_admin';
    public const ADMIN = 'admin';
    public const MODERATOR = 'moderator';
    public const USER = 'user';

    // Role hierarchy: higher roles inherit lower role permissions
    public const HIERARCHY = [
        self::SUPER_ADMIN => 100,
        self::ADMIN => 75,
        self::MODERATOR => 50,
        self::USER => 10,
    ];

    // Default permissions per role
    public const PERMISSIONS = [
        self::SUPER_ADMIN => [
            Permission::USER_VIEW,
            Permission::USER_CREATE,
            Permission::USER_EDIT,
            Permission::USER_DELETE,
            Permission::CONTENT_MODERATE,
            Permission::CONTENT_DELETE,
            Permission::SETTINGS_VIEW,
            Permission::SETTINGS_EDIT,
            Permission::AUDIT_VIEW,
            Permission::ROLE_MANAGE,
        ],
        self::ADMIN => [
            Permission::USER_VIEW,
            Permission::USER_CREATE,
            Permission::USER_EDIT,
            Permission::CONTENT_MODERATE,
            Permission::CONTENT_DELETE,
            Permission::SETTINGS_VIEW,
            Permission::AUDIT_VIEW,
        ],
        self::MODERATOR => [
            Permission::USER_VIEW,
            Permission::CONTENT_MODERATE,
        ],
        self::USER => [
            Permission::USER_VIEW,
        ],
    ];
}

class RBACService {
    private PDO $pdo;
    private LoggerInterface $logger;
    private array $permissionCache = [];

    public function __construct(PDO $pdo, LoggerInterface $logger) {
        $this->pdo = $pdo;
        $this->logger = $logger;
    }

    public function getUserWithPermissions(int $userId): ?array {
        // Check cache first
        if (isset($this->permissionCache[$userId])) {
            return $this->permissionCache[$userId];
        }

        $stmt = $this->pdo->prepare("
            SELECT 
                u.id,
                u.username,
                u.email,
                u.role,
                u.is_active,
                u.mfa_enabled,
                COALESCE(
                    JSON_ARRAYAGG(up.permission),
                    JSON_ARRAY()
                ) as custom_permissions
            FROM users u
            LEFT JOIN user_permissions up ON u.id = up.user_id
            WHERE u.id = ?
            GROUP BY u.id
        ");
        $stmt->execute([$userId]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$user || !$user['is_active']) {
            return null;
        }

        // Merge role permissions with custom permissions
        $rolePermissions = Role::PERMISSIONS[$user['role']] ?? [];
        $customPermissions = json_decode($user['custom_permissions'], true) ?? [];
        $user['effective_permissions'] = array_unique(
            array_merge($rolePermissions, $customPermissions)
        );

        // Cache for request duration
        $this->permissionCache[$userId] = $user;

        return $user;
    }

    public function authorize(
        int $userId,
        string $permission,
        array $context = []
    ): AuthorizationResult {
        $user = $this->getUserWithPermissions($userId);

        if (!$user) {
            $this->logAuthorizationFailure($userId, $permission, 'User not found or inactive');
            return new AuthorizationResult(false, 'User not found');
        }

        // Check if user has the required permission
        if (!in_array($permission, $user['effective_permissions'], true)) {
            $this->logAuthorizationFailure(
                $userId,
                $permission,
                'Permission denied',
                $context
            );
            return new AuthorizationResult(
                false,
                'Insufficient permissions',
                $user['role']
            );
        }

        // Additional context-based checks (ABAC)
        if (!$this->checkContextualPermissions($user, $permission, $context)) {
            $this->logAuthorizationFailure(
                $userId,
                $permission,
                'Contextual check failed',
                $context
            );
            return new AuthorizationResult(
                false,
                'Action not permitted in this context'
            );
        }

        $this->logAuthorizationSuccess($userId, $permission, $context);
        return new AuthorizationResult(true, 'Authorized', $user['role']);
    }

    private function checkContextualPermissions(
        array $user,
        string $permission,
        array $context
    ): bool {
        // Prevent users from modifying users with higher roles
        if (str_starts_with($permission, 'user:') && isset($context['target_user_id'])) {
            $targetUser = $this->getUserWithPermissions($context['target_user_id']);
            if ($targetUser) {
                $userLevel = Role::HIERARCHY[$user['role']] ?? 0;
                $targetLevel = Role::HIERARCHY[$targetUser['role']] ?? 0;

                // Cannot modify users at same or higher level (except super_admin)
                if ($targetLevel >= $userLevel && $user['role'] !== Role::SUPER_ADMIN) {
                    return false;
                }
            }
        }

        // Time-based restrictions (e.g., no deletions during maintenance)
        if (str_ends_with($permission, ':delete')) {
            $maintenanceMode = getenv('MAINTENANCE_MODE') === 'true';
            if ($maintenanceMode && $user['role'] !== Role::SUPER_ADMIN) {
                return false;
            }
        }

        return true;
    }

    private function logAuthorizationFailure(
        int $userId,
        string $permission,
        string $reason,
        array $context = []
    ): void {
        $this->logger->warning('Authorization failed', [
            'user_id' => $userId,
            'permission' => $permission,
            'reason' => $reason,
            'context' => $context,
            'ip_address' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown',
            'timestamp' => date('c'),
        ]);

        // Store in database for security dashboard
        $stmt = $this->pdo->prepare("
            INSERT INTO security_events 
            (event_type, user_id, details, ip_address, created_at)
            VALUES ('auth_failure', ?, ?, ?, NOW())
        ");
        $stmt->execute([
            $userId,
            json_encode([
                'permission' => $permission,
                'reason' => $reason,
                'context' => $context,
            ]),
            $_SERVER['REMOTE_ADDR'] ?? 'unknown',
        ]);
    }

    private function logAuthorizationSuccess(
        int $userId,
        string $permission,
        array $context
    ): void {
        // Log sensitive operations
        $sensitivePermissions = [
            Permission::USER_DELETE,
            Permission::ROLE_MANAGE,
            Permission::SETTINGS_EDIT,
        ];

        if (in_array($permission, $sensitivePermissions, true)) {
            $this->logger->info('Sensitive operation authorized', [
                'user_id' => $userId,
                'permission' => $permission,
                'context' => $context,
                'ip_address' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
                'timestamp' => date('c'),
            ]);
        }
    }
}

class AuthorizationResult {
    public bool $allowed;
    public string $message;
    public ?string $userRole;

    public function __construct(
        bool $allowed,
        string $message,
        ?string $userRole = null
    ) {
        $this->allowed = $allowed;
        $this->message = $message;
        $this->userRole = $userRole;
    }
}

// Middleware for automatic authorization
class AuthorizationMiddleware {
    private RBACService $rbac;

    public function __construct(RBACService $rbac) {
        $this->rbac = $rbac;
    }

    public function require(string $permission, array $context = []): void {
        $userId = $_SESSION['user_id'] ?? null;

        if (!$userId) {
            http_response_code(401);
            header('Content-Type: application/json');
            exit(json_encode([
                'error' => 'Authentication required',
                'code' => 'UNAUTHENTICATED',
            ]));
        }

        $result = $this->rbac->authorize($userId, $permission, $context);

        if (!$result->allowed) {
            http_response_code(403);
            header('Content-Type: application/json');
            exit(json_encode([
                'error' => 'Access denied',
                'code' => 'FORBIDDEN',
                'message' => $result->message,
            ]));
        }
    }
}

// Usage in controller
class UserManagementController {
    private PDO $pdo;
    private AuthorizationMiddleware $auth;

    public function __construct(PDO $pdo, AuthorizationMiddleware $auth) {
        $this->pdo = $pdo;
        $this->auth = $auth;
    }

    public function deleteUser(int $targetUserId): array {
        // Authorization check with context
        $this->auth->require(
            Permission::USER_DELETE,
            ['target_user_id' => $targetUserId]
        );

        // Validate target exists
        $stmt = $this->pdo->prepare("SELECT id FROM users WHERE id = ?");
        $stmt->execute([$targetUserId]);
        if (!$stmt->fetch()) {
            http_response_code(404);
            return ['error' => 'User not found'];
        }

        // Soft delete with audit trail
        $stmt = $this->pdo->prepare("
            UPDATE users 
            SET is_active = 0, 
                deleted_at = NOW(),
                deleted_by = ?
            WHERE id = ?
        ");
        $stmt->execute([$_SESSION['user_id'], $targetUserId]);

        return ['success' => true, 'message' => 'User deactivated'];
    }
}
?>
```

**Defense in Depth Layers**:

1. **Authentication Layer**: Session validation before any authorization check
```php
if (!isset($_SESSION['user_id']) || !$this->validateSession()) {
    throw new UnauthenticatedException();
}
```

2. **Role-Based Layer**: Check if user's role grants the required permission
```php
$rolePermissions = Role::PERMISSIONS[$user['role']] ?? [];
if (!in_array($permission, $rolePermissions)) {
    throw new UnauthorizedException();
}
```

3. **Contextual Layer**: Hierarchical checks prevent privilege escalation
```php
if ($targetUserLevel >= $currentUserLevel) {
    throw new PrivilegeEscalationException();
}
```

**Additional Protections**:

- **Permission caching**: Reduces database load while maintaining security
- **Comprehensive audit logging**: All authorization decisions logged for forensics
- **Soft deletes**: Critical data preserved for recovery and investigation
- **Rate limiting on sensitive endpoints**: Prevents automated abuse
- **MFA enforcement for admin roles**: Add `if ($user['role'] !== Role::USER && !$user['mfa_enabled'])` check
- **IP allowlisting for super_admin**: Restrict highest privilege to known IPs
- **Session binding**: Tie sessions to IP/User-Agent to prevent hijacking

