**SECURE VERSION**:

```csharp
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using System.Security.Claims;
using System.Collections.Generic;
using System.Linq;

namespace AdminPanel.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Roles = "Admin")]  // Server-side role requirement
    public class AdminController : ControllerBase
    {
        private readonly AppDbContext _context;
        private readonly ILogger<AdminController> _logger;

        public AdminController(AppDbContext context, ILogger<AdminController> logger)
        {
            _context = context;
            _logger = logger;
        }

        [HttpGet("users")]
        [Authorize(Policy = "RequireAdminRole")]  // Policy-based authorization
        public IActionResult GetAllUsers()
        {
            var adminId = User.FindFirstValue(ClaimTypes.NameIdentifier);
            _logger.LogInformation(
                "Admin {AdminId} accessed user list at {Time}",
                adminId, DateTime.UtcNow);

            // Return only non-sensitive data
            var users = _context.Users
                .Select(u => new UserDto {
                    Id = u.Id,
                    Email = MaskEmail(u.Email),
                    CreatedAt = u.CreatedAt,
                    IsActive = u.IsActive
                    // No password hashes, SSNs, or sensitive data
                })
                .ToList();

            return Ok(users);
        }

        [HttpDelete("users/{id}")]
        [Authorize(Policy = "RequireSuperAdmin")]  // Higher privilege needed
        public IActionResult DeleteUser(int id)
        {
            var adminId = User.FindFirstValue(ClaimTypes.NameIdentifier);

            // Prevent self-deletion
            if (id.ToString() == adminId)
            {
                _logger.LogWarning("Admin {AdminId} attempted self-deletion", adminId);
                return BadRequest(new { error = "Cannot delete your own account" });
            }

            var user = _context.Users.Find(id);
            if (user == null)
            {
                return NotFound();
            }

            // Soft delete with audit trail
            user.IsDeleted = true;
            user.DeletedBy = adminId;
            user.DeletedAt = DateTime.UtcNow;
            _context.SaveChanges();

            _logger.LogWarning(
                "Admin {AdminId} deleted user {UserId} at {Time}",
                adminId, id, DateTime.UtcNow);

            return Ok(new { message = "User deactivated" });
        }

        private static string MaskEmail(string email)
        {
            var parts = email.Split('@');
            if (parts.Length != 2 || parts[0].Length < 2)
                return "***@***.***";
            return $"{parts[0][0]}***@{parts[1]}";
        }
    }
}
```

**Key Security Controls**:
- **[Authorize] attribute**: Server enforces authentication and role checks before any code runs
- **Policy-based authorization**: Fine-grained control (RequireAdminRole, RequireSuperAdmin) allows different access levels
- **Data minimization**: Only return non-sensitive fields, mask PII even for admins
- **Audit logging**: Every administrative action is logged with admin ID and timestamp
- **Soft deletes**: Maintain audit trail instead of permanent deletion

Excellent question! You need a robust Role-Based Access Control (RBAC) or Claims-Based authorization system. ASP.NET Core's policy-based authorization is perfect for this - it lets you define granular permissions that map to specific actions.

**PRODUCTION PATTERN**:

```csharp
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using System;
using System.Security.Claims;
using System.Threading.Tasks;
using System.Collections.Generic;

namespace AdminPanel.Authorization
{
    // Define permission constants
    public static class Permissions
    {
        public const string ViewUsers = "users.view";
        public const string EditUsers = "users.edit";
        public const string DeleteUsers = "users.delete";
        public const string ViewAuditLogs = "audit.view";
        public const string ManageRoles = "roles.manage";
        public const string ViewConfig = "config.view";
        public const string EditConfig = "config.edit";
    }

    // Custom authorization requirement
    public class PermissionRequirement : IAuthorizationRequirement
    {
        public string Permission { get; }
        public PermissionRequirement(string permission)
        {
            Permission = permission;
        }
    }

    // Permission handler that checks user claims
    public class PermissionHandler : AuthorizationHandler<PermissionRequirement>
    {
        private readonly IPermissionService _permissionService;
        private readonly ILogger<PermissionHandler> _logger;

        public PermissionHandler(
            IPermissionService permissionService,
            ILogger<PermissionHandler> logger)
        {
            _permissionService = permissionService;
            _logger = logger;
        }

        protected override async Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            PermissionRequirement requirement)
        {
            var userId = context.User.FindFirstValue(ClaimTypes.NameIdentifier);

            if (string.IsNullOrEmpty(userId))
            {
                _logger.LogWarning("Authorization failed: No user identity");
                context.Fail();
                return;
            }

            // Check permission from database (cached)
            var hasPermission = await _permissionService
                .UserHasPermissionAsync(userId, requirement.Permission);

            if (hasPermission)
            {
                _logger.LogDebug(
                    "User {UserId} authorized for {Permission}",
                    userId, requirement.Permission);
                context.Succeed(requirement);
            }
            else
            {
                _logger.LogWarning(
                    "User {UserId} denied access to {Permission}",
                    userId, requirement.Permission);
                context.Fail();
            }
        }
    }
}

namespace AdminPanel.Controllers
{
    [ApiController]
    [Route("api/admin")]
    [Authorize]  // Require authentication for all endpoints
    public class SecureAdminController : ControllerBase
    {
        private readonly AppDbContext _context;
        private readonly ILogger<SecureAdminController> _logger;
        private readonly IAuditService _auditService;

        public SecureAdminController(
            AppDbContext context,
            ILogger<SecureAdminController> logger,
            IAuditService auditService)
        {
            _context = context;
            _logger = logger;
            _auditService = auditService;
        }

        // Read-only admins can access this
        [HttpGet("users")]
        [Authorize(Policy = "users.view")]
        public async Task<IActionResult> GetUsers([FromQuery] int page = 1)
        {
            var adminId = GetCurrentUserId();

            await _auditService.LogAsync(new AuditEntry
            {
                UserId = adminId,
                Action = "VIEW_USERS",
                Resource = "UserList",
                Timestamp = DateTime.UtcNow,
                IpAddress = GetClientIp(),
                UserAgent = Request.Headers["User-Agent"].ToString()
            });

            var users = await _context.Users
                .Where(u => !u.IsDeleted)
                .OrderBy(u => u.Id)
                .Skip((page - 1) * 50)
                .Take(50)
                .Select(u => new UserSummaryDto
                {
                    Id = u.Id,
                    Email = MaskPII(u.Email),
                    Role = u.Role,
                    LastLogin = u.LastLogin,
                    IsActive = u.IsActive
                })
                .ToListAsync();

            return Ok(new { users, page, pageSize = 50 });
        }

        // Only admins with edit permission
        [HttpPut("users/{id}")]
        [Authorize(Policy = "users.edit")]
        public async Task<IActionResult> UpdateUser(int id, [FromBody] UpdateUserDto dto)
        {
            var adminId = GetCurrentUserId();
            var user = await _context.Users.FindAsync(id);

            if (user == null)
                return NotFound();

            // Prevent privilege escalation
            if (dto.Role == "SuperAdmin" && 
                !User.HasClaim("permission", Permissions.ManageRoles))
            {
                _logger.LogWarning(
                    "Admin {AdminId} attempted privilege escalation for user {UserId}",
                    adminId, id);

                await _auditService.LogSecurityEventAsync(
                    "PRIVILEGE_ESCALATION_ATTEMPT",
                    adminId,
                    $"Attempted to set user {id} as SuperAdmin");

                return Forbid();
            }

            // Track changes for audit
            var changes = new Dictionary<string, object>();
            if (user.Email != dto.Email)
                changes["Email"] = new { Old = user.Email, New = dto.Email };
            if (user.Role != dto.Role)
                changes["Role"] = new { Old = user.Role, New = dto.Role };

            user.Email = dto.Email;
            user.Role = dto.Role;
            user.ModifiedBy = adminId;
            user.ModifiedAt = DateTime.UtcNow;

            await _context.SaveChangesAsync();

            await _auditService.LogAsync(new AuditEntry
            {
                UserId = adminId,
                Action = "UPDATE_USER",
                Resource = $"User:{id}",
                Changes = System.Text.Json.JsonSerializer.Serialize(changes),
                Timestamp = DateTime.UtcNow,
                IpAddress = GetClientIp()
            });

            return Ok(new { message = "User updated" });
        }

        // Super admin only - requires highest privilege
        [HttpDelete("users/{id}")]
        [Authorize(Policy = "users.delete")]
        public async Task<IActionResult> DeleteUser(int id)
        {
            var adminId = GetCurrentUserId();

            // Additional security: require re-authentication for destructive actions
            var recentAuth = User.FindFirstValue("auth_time");
            if (recentAuth == null || 
                DateTime.Parse(recentAuth) < DateTime.UtcNow.AddMinutes(-5))
            {
                return StatusCode(403, new { 
                    error = "reauthentication_required",
                    message = "Please re-authenticate to perform this action"
                });
            }

            var user = await _context.Users.FindAsync(id);
            if (user == null)
                return NotFound();

            // Prevent deleting other super admins
            if (user.Role == "SuperAdmin")
            {
                _logger.LogCritical(
                    "Admin {AdminId} attempted to delete SuperAdmin {UserId}",
                    adminId, id);
                return Forbid();
            }

            // Soft delete with full audit
            user.IsDeleted = true;
            user.DeletedBy = adminId;
            user.DeletedAt = DateTime.UtcNow;
            user.DeletionReason = "Admin deletion";

            await _context.SaveChangesAsync();

            await _auditService.LogAsync(new AuditEntry
            {
                UserId = adminId,
                Action = "DELETE_USER",
                Resource = $"User:{id}",
                Severity = AuditSeverity.Critical,
                Timestamp = DateTime.UtcNow,
                IpAddress = GetClientIp()
            });

            return Ok(new { message = "User deleted" });
        }

        private string GetCurrentUserId() =>
            User.FindFirstValue(ClaimTypes.NameIdentifier);

        private string GetClientIp() =>
            HttpContext.Connection.RemoteIpAddress?.ToString() ?? "unknown";

        private static string MaskPII(string value)
        {
            if (string.IsNullOrEmpty(value) || value.Length < 4)
                return "****";
            return $"{value[0]}***{value[^1]}";
        }
    }
}

// Startup.cs / Program.cs configuration
public static class AuthorizationConfig
{
    public static void ConfigureAuthorization(this IServiceCollection services)
    {
        services.AddAuthorization(options =>
        {
            // Define policies for each permission
            options.AddPolicy("users.view", policy =>
                policy.Requirements.Add(new PermissionRequirement(Permissions.ViewUsers)));

            options.AddPolicy("users.edit", policy =>
                policy.Requirements.Add(new PermissionRequirement(Permissions.EditUsers)));

            options.AddPolicy("users.delete", policy =>
            {
                policy.Requirements.Add(new PermissionRequirement(Permissions.DeleteUsers));
                policy.RequireAuthenticatedUser();
                policy.RequireClaim("mfa_verified", "true");  // Require MFA
            });

            // Fallback policy - deny by default
            options.FallbackPolicy = new AuthorizationPolicyBuilder()
                .RequireAuthenticatedUser()
                .Build();
        });

        services.AddScoped<IAuthorizationHandler, PermissionHandler>();
        services.AddScoped<IPermissionService, CachedPermissionService>();
    }
}
```

**Defense in Depth Layers**:

1. **Authentication Layer**: All endpoints require valid JWT/session token
