**Additional Protections**:
- **MFA requirement**: Destructive actions require `mfa_verified` claim
- **Comprehensive audit logging**: Every action logged with user, IP, timestamp, and changes
- **Privilege escalation prevention**: Cannot promote users to roles higher than your own
- **Soft deletes**: Never permanently delete data, maintain full history
- **Rate limiting**: Add `[RateLimit("admin", 100, 60)]` to prevent abuse
- **Data masking**: PII is masked even for authorized admins unless specifically needed
- **IP-based restrictions**: Production can add `[RequireVpn]` attribute for admin endpoints

**For complex authorization scenarios, you need a proper Role-Based Access Control (RBAC) or Attribute-Based Access Control (ABAC) system with server-side permission resolution.**

**PRODUCTION PATTERN**:

```python
from flask import Flask, request, jsonify, g
from functools import wraps
from enum import Enum, auto
from typing import Set, List, Callable
import sqlite3
import jwt
import os
import logging
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY')

# Configure security logging
security_logger = logging.getLogger('security')
security_logger.setLevel(logging.INFO)
handler = logging.FileHandler('/var/log/app/security.log')
handler.setFormatter(logging.Formatter(
    '%(asctime)s - %(levelname)s - %(message)s'
))
security_logger.addHandler(handler)


class Permission(Enum):
    """Granular permissions - defined server-side only"""
    READ_USERS = auto()
    EDIT_USERS = auto()
    DELETE_USERS = auto()
    READ_POSTS = auto()
    EDIT_POSTS = auto()
    DELETE_POSTS = auto()
    MANAGE_ROLES = auto()
    VIEW_AUDIT_LOG = auto()
    SYSTEM_ADMIN = auto()


# Role-to-permission mapping - SERVER-SIDE ONLY
ROLE_PERMISSIONS = {
    'viewer': {
        Permission.READ_USERS,
        Permission.READ_POSTS,
    },
    'editor': {
        Permission.READ_USERS,
        Permission.READ_POSTS,
        Permission.EDIT_POSTS,
    },
    'moderator': {
        Permission.READ_USERS,
        Permission.READ_POSTS,
        Permission.EDIT_POSTS,
        Permission.DELETE_POSTS,
    },
    'admin': {
        Permission.READ_USERS,
        Permission.EDIT_USERS,
        Permission.DELETE_USERS,
        Permission.READ_POSTS,
        Permission.EDIT_POSTS,
        Permission.DELETE_POSTS,
        Permission.MANAGE_ROLES,
        Permission.VIEW_AUDIT_LOG,
    },
    'superadmin': {
        Permission.SYSTEM_ADMIN,  # Implies all permissions
    }
}


class AuthorizationService:
    """Centralized server-side authorization service"""

    def __init__(self, db_connection):
        self.db = db_connection

    def get_user_permissions(self, user_id: int) -> Set[Permission]:
        """Load all permissions from database - NEVER from client"""
        cursor = self.db.cursor()

        # Get user's roles from database
        cursor.execute("""
            SELECT r.name 
            FROM roles r
            JOIN user_roles ur ON r.id = ur.role_id
            WHERE ur.user_id = ? AND ur.is_active = 1
        """, (user_id,))

        user_roles = [row[0] for row in cursor.fetchall()]

        # Get custom permissions assigned directly to user
        cursor.execute("""
            SELECT p.name
            FROM permissions p
            JOIN user_permissions up ON p.id = up.permission_id
            WHERE up.user_id = ? AND up.is_active = 1
        """, (user_id,))

        custom_permissions = {row[0] for row in cursor.fetchall()}

        # Aggregate all permissions from roles
        all_permissions = set()
        for role in user_roles:
            if role in ROLE_PERMISSIONS:
                all_permissions.update(ROLE_PERMISSIONS[role])

        # Add custom permissions
        for perm_name in custom_permissions:
            try:
                all_permissions.add(Permission[perm_name])
            except KeyError:
                security_logger.warning(
                    f"Unknown permission '{perm_name}' for user {user_id}"
                )

        # Check for superadmin - grants all permissions
        if Permission.SYSTEM_ADMIN in all_permissions:
            all_permissions = set(Permission)

        return all_permissions

    def check_permission(
        self, 
        user_id: int, 
        required: Permission,
        resource_id: int = None,
        resource_type: str = None
    ) -> bool:
        """Check if user has specific permission, with optional resource context"""

        user_permissions = self.get_user_permissions(user_id)

        # Basic permission check
        if required not in user_permissions:
            return False

        # Resource-level authorization (ABAC component)
        if resource_id and resource_type:
            return self._check_resource_access(
                user_id, resource_id, resource_type, required
            )

        return True

    def _check_resource_access(
        self,
        user_id: int,
        resource_id: int,
        resource_type: str,
        action: Permission
    ) -> bool:
        """Check resource-level access (e.g., own posts only)"""
        cursor = self.db.cursor()

        if resource_type == 'post':
            # Users can edit their own posts even without EDIT_POSTS permission
            cursor.execute(
                "SELECT author_id FROM posts WHERE id = ?",
                (resource_id,)
            )
            result = cursor.fetchone()
            if result and result[0] == user_id:
                return True

        return True  # If has permission, allow unless resource-specific rule denies


def get_db():
    if 'db' not in g:
        g.db = sqlite3.connect('app.db')
    return g.db


def get_auth_service():
    if 'auth_service' not in g:
        g.auth_service = AuthorizationService(get_db())
    return g.auth_service


def authenticate(f):
    """Authentication decorator - verifies identity"""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization', '').replace('Bearer ', '')

        if not token:
            return jsonify({'error': 'Authentication required'}), 401

        try:
            payload = jwt.decode(
                token,
                app.config['SECRET_KEY'],
                algorithms=['HS256']
            )

            # Load user from database
            cursor = get_db().cursor()
            cursor.execute(
                "SELECT id, username, is_active FROM users WHERE id = ?",
                (payload['user_id'],)
            )
            user = cursor.fetchone()

            if not user:
                security_logger.warning(
                    f"Token for non-existent user: {payload['user_id']}"
                )
                return jsonify({'error': 'User not found'}), 401

            if not user[2]:  # is_active check
                security_logger.warning(
                    f"Disabled user attempted access: {user[0]}"
                )
                return jsonify({'error': 'Account disabled'}), 403

            g.current_user_id = user[0]
            g.current_username = user[1]

        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token expired'}), 401
        except jwt.InvalidTokenError as e:
            security_logger.warning(f"Invalid token attempt: {e}")
            return jsonify({'error': 'Invalid token'}), 401

        return f(*args, **kwargs)
    return decorated


def require_permission(*required_permissions: Permission):
    """Authorization decorator - verifies permissions server-side"""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            auth_service = get_auth_service()
            user_permissions = auth_service.get_user_permissions(
                g.current_user_id
            )

            # Check all required permissions
            missing = []
            for perm in required_permissions:
                if perm not in user_permissions:
                    missing.append(perm.name)

            if missing:
                security_logger.warning(
                    f"AUTHORIZATION_DENIED | "
                    f"user_id={g.current_user_id} | "
                    f"path={request.path} | "
                    f"method={request.method} | "
                    f"missing_permissions={missing} | "
                    f"ip={request.remote_addr}"
                )
                return jsonify({
                    'error': 'Insufficient permissions',
                    'required': missing
                }), 403

            # Log successful authorization for audit trail
            security_logger.info(
                f"AUTHORIZATION_GRANTED | "
                f"user_id={g.current_user_id} | "
                f"path={request.path} | "
                f"method={request.method}"
            )

            return f(*args, **kwargs)
        return decorated
    return decorator


# Example endpoints with proper authorization

@app.route('/api/users', methods=['GET'])
@authenticate
@require_permission(Permission.READ_USERS)
def list_users():
    """List users - requires READ_USERS permission"""
    cursor = get_db().cursor()
    cursor.execute("SELECT id, username, email, created_at FROM users")
    users = [
        {'id': r[0], 'username': r[1], 'email': r[2], 'created_at': r[3]}
        for r in cursor.fetchall()
    ]
    return jsonify({'users': users})


@app.route('/api/users/<int:user_id>', methods=['DELETE'])
@authenticate
@require_permission(Permission.DELETE_USERS)
def delete_user(user_id):
    """Delete user - requires DELETE_USERS permission"""
    # Prevent self-deletion
    if user_id == g.current_user_id:
        return jsonify({'error': 'Cannot delete yourself'}), 400

    cursor = get_db().cursor()
    cursor.execute("DELETE FROM users WHERE id = ?", (user_id,))
    get_db().commit()

    security_logger.info(
        f"USER_DELETED | deleted_user_id={user_id} | "
        f"by_user_id={g.current_user_id}"
    )

    return jsonify({'message': 'User deleted'})


@app.route('/api/posts/<int:post_id>', methods=['PUT'])
@authenticate
def edit_post(post_id):
    """Edit post - requires EDIT_POSTS or ownership"""
    auth_service = get_auth_service()

    # Check resource-level access
    cursor = get_db().cursor()
    cursor.execute("SELECT author_id FROM posts WHERE id = ?", (post_id,))
    post = cursor.fetchone()

    if not post:
        return jsonify({'error': 'Post not found'}), 404

    # Allow if user owns the post OR has EDIT_POSTS permission
    is_owner = post[0] == g.current_user_id
    has_edit_permission = auth_service.check_permission(
        g.current_user_id, Permission.EDIT_POSTS
    )

    if not is_owner and not has_edit_permission:
        security_logger.warning(
            f"EDIT_POST_DENIED | post_id={post_id} | "
            f"user_id={g.current_user_id} | is_owner={is_owner}"
        )
        return jsonify({'error': 'Cannot edit this post'}), 403

    # Proceed with edit
    data = request.get_json()
    cursor.execute(
        "UPDATE posts SET content = ?, updated_at = ? WHERE id = ?",
        (data.get('content'), datetime.utcnow().isoformat(), post_id)
    )
    get_db().commit()

    return jsonify({'message': 'Post updated'})


@app.teardown_appcontext
def close_db(exception):
    db = g.pop('db', None)
    if db is not None:
        db.close()
