For granular permissions, implement Role-Based Access Control (RBAC) or Attribute-Based Access Control (ABAC) entirely on the server. The client should only receive what it's authorized to see.

**PRODUCTION PATTERN**:

```javascript
// permissions.js - Centralized permission definitions
const PERMISSIONS = {
  'users:read': ['viewer', 'editor', 'admin'],
  'users:create': ['editor', 'admin'],
  'users:update': ['editor', 'admin'],
  'users:delete': ['admin'],
  'reports:read': ['viewer', 'editor', 'admin'],
  'reports:export': ['editor', 'admin'],
  'settings:read': ['admin'],
  'settings:update': ['admin']
};

const hasPermission = (userRole, permission) => {
  const allowedRoles = PERMISSIONS[permission];
  if (!allowedRoles) {
    console.error(`Unknown permission: ${permission}`);
    return false; // Fail closed - deny unknown permissions
  }
  return allowedRoles.includes(userRole);
};

module.exports = { PERMISSIONS, hasPermission };

// middleware/authorization.js
const { hasPermission } = require('./permissions');

const requirePermission = (permission) => {
  return async (req, res, next) => {
    // Fetch fresh role from database - never trust cached/client data
    const user = await db.query(
      'SELECT id, role, is_active FROM users WHERE id = $1',
      [req.user.id]
    );

    if (!user || !user.is_active) {
      return res.status(401).json({ error: 'Account inactive or not found' });
    }

    if (!hasPermission(user.role, permission)) {
      // Log unauthorized access attempts
      await auditLog({
        action: 'PERMISSION_DENIED',
        userId: req.user.id,
        userRole: user.role,
        requiredPermission: permission,
        resource: req.originalUrl,
        ip: req.ip,
        userAgent: req.get('User-Agent'),
        timestamp: new Date().toISOString()
      });

      return res.status(403).json({
        error: 'Insufficient permissions',
        required: permission
      });
    }

    req.userRole = user.role;
    next();
  };
};

// Resource-level authorization for object ownership
const requireOwnershipOrAdmin = (resourceFetcher) => {
  return async (req, res, next) => {
    const resource = await resourceFetcher(req);

    if (!resource) {
      return res.status(404).json({ error: 'Resource not found' });
    }

    const isOwner = resource.owner_id === req.user.id;
    const isAdmin = req.userRole === 'admin';

    if (!isOwner && !isAdmin) {
      await auditLog({
        action: 'OWNERSHIP_VIOLATION',
        userId: req.user.id,
        resourceId: resource.id,
        resourceOwnerId: resource.owner_id,
        timestamp: new Date().toISOString()
      });

      return res.status(403).json({ error: 'Access denied' });
    }

    req.resource = resource;
    next();
  };
};

module.exports = { requirePermission, requireOwnershipOrAdmin };

