        if (currentUser == null) {
            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
            response.getWriter().write("{\"error\": \"Authentication required\"}");
            auditLogger.logUnauthorizedAccess(request, "No session");
            return;
        }

        // SECURE: Server-side authorization check - NEVER trust client
        if (!authService.hasRole(currentUser, Role.ADMIN)) {
            response.setStatus(HttpServletResponse.SC_FORBIDDEN);
            response.getWriter().write("{\"error\": \"Admin privileges required\"}");
            auditLogger.logForbiddenAccess(currentUser, request.getPathInfo());
            logger.warning("Authorization bypass attempt by user: " + currentUser.getId());
            return;
        }

        String pathInfo = request.getPathInfo();

        try {
            if ("/deleteUser".equals(pathInfo)) {
                handleDeleteUser(request, response, currentUser);
            } else if ("/promoteToAdmin".equals(pathInfo)) {
                handlePromoteToAdmin(request, response, currentUser);
            } else if ("/exportAllUsers".equals(pathInfo)) {
                handleExportUsers(request, response, currentUser);
            } else {
                response.setStatus(HttpServletResponse.SC_NOT_FOUND);
            }
        } catch (Exception e) {
            logger.severe("Admin operation failed: " + e.getMessage());
            response.setStatus(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
            response.getWriter().write("{\"error\": \"Operation failed\"}");
        }
    }

    private void handleDeleteUser(HttpServletRequest request, 
            HttpServletResponse response, User admin) throws IOException {
        String userId = request.getParameter("userId");

        // Additional validation
        if (userId == null || !userId.matches("^[0-9]+$")) {
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            return;
        }

        // Audit log BEFORE action
        auditLogger.logAdminAction(admin.getId(), "DELETE_USER", userId);
        deleteUser(userId);
        response.getWriter().write("{\"status\": \"deleted\"}");
    }

