**Key Security Controls**:
- **Server-side authentication**: Validates user identity on every request via session or token
- **Server-side authorization**: Checks user role/permissions before executing any privileged action
- **Audit logging**: Records all admin actions for forensics and compliance
- **Input validation**: Validates all parameters on the server, never trusting client data

Excellent question! For fine-grained authorization, you need a robust Role-Based Access Control (RBAC) or Attribute-Based Access Control (ABAC) system implemented entirely on the server. Here's a production-ready pattern:

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import java.io.*;
import java.util.*;
import java.util.logging.Logger;
import java.time.Instant;

// Permission definitions - granular capabilities
public enum Permission {
    USER_VIEW,
    USER_CREATE,
    USER_UPDATE,
    USER_DELETE,
    REPORT_VIEW,
    REPORT_EXPORT,
    SYSTEM_CONFIG,
    AUDIT_LOG_VIEW
}

// Role definitions with specific permissions
public enum Role {
    VIEWER(EnumSet.of(Permission.USER_VIEW, Permission.REPORT_VIEW)),
    ANALYST(EnumSet.of(Permission.USER_VIEW, Permission.REPORT_VIEW, Permission.REPORT_EXPORT)),
    USER_MANAGER(EnumSet.of(Permission.USER_VIEW, Permission.USER_CREATE, Permission.USER_UPDATE)),
    ADMIN(EnumSet.of(Permission.USER_VIEW, Permission.USER_CREATE, Permission.USER_UPDATE, 
                      Permission.USER_DELETE, Permission.REPORT_VIEW, Permission.REPORT_EXPORT)),
    SUPER_ADMIN(EnumSet.allOf(Permission.class));

    private final Set<Permission> permissions;

    Role(Set<Permission> permissions) {
        this.permissions = Collections.unmodifiableSet(permissions);
    }

    public boolean hasPermission(Permission permission) {
        return permissions.contains(permission);
    }

    public Set<Permission> getPermissions() {
        return permissions;
    }
}

// Authorization service with caching and context-aware checks
public class AuthorizationService {

    private static final Logger logger = Logger.getLogger(AuthorizationService.class.getName());
    private final UserRepository userRepository;
    private final AuditService auditService;
    private final RateLimiter rateLimiter;

    public AuthorizationService(UserRepository userRepository, 
            AuditService auditService, RateLimiter rateLimiter) {
        this.userRepository = userRepository;
        this.auditService = auditService;
        this.rateLimiter = rateLimiter;
    }

    public AuthorizationResult authorize(HttpServletRequest request, 
            Permission requiredPermission) {

        // Step 1: Extract and validate authentication
        String sessionId = extractSessionId(request);
        if (sessionId == null) {
            return AuthorizationResult.unauthenticated("No session token");
        }

        // Step 2: Rate limiting check
        String clientIp = getClientIp(request);
        if (!rateLimiter.allowRequest(clientIp)) {
            auditService.logRateLimitExceeded(clientIp, sessionId);
            return AuthorizationResult.rateLimited();
        }

        // Step 3: Load user and validate session
        User user = userRepository.findBySessionId(sessionId);
        if (user == null || user.isSessionExpired()) {
            return AuthorizationResult.unauthenticated("Invalid or expired session");
        }

        // Step 4: Check account status
        if (user.isLocked() || user.isDisabled()) {
            auditService.logLockedAccountAccess(user.getId(), clientIp);
            return AuthorizationResult.forbidden("Account is locked or disabled");
        }

        // Step 5: Permission check
        if (!user.getRole().hasPermission(requiredPermission)) {
            auditService.logUnauthorizedAttempt(user.getId(), requiredPermission, 
                    request.getRequestURI());
            logger.warning(String.format(
                "Authorization denied: User %s attempted %s on %s",
                user.getId(), requiredPermission, request.getRequestURI()));
            return AuthorizationResult.forbidden(
                "Insufficient permissions for this action");
        }

        // Step 6: Context-aware checks (time, location, etc.)
        if (requiredPermission == Permission.SYSTEM_CONFIG && 
                !isFromTrustedNetwork(clientIp)) {
            auditService.logSuspiciousAccess(user.getId(), clientIp, 
                    "Config access from untrusted network");
            return AuthorizationResult.forbidden(
                "This action requires trusted network access");
        }

        return AuthorizationResult.authorized(user);
    }

    // Resource-level authorization (user can only access their own data)
    public AuthorizationResult authorizeResourceAccess(HttpServletRequest request,
            Permission requiredPermission, String resourceOwnerId) {

        AuthorizationResult baseResult = authorize(request, requiredPermission);
        if (!baseResult.isAuthorized()) {
            return baseResult;
        }

        User user = baseResult.getUser();

        // Super admins can access all resources
        if (user.getRole() == Role.SUPER_ADMIN) {
            return baseResult;
        }

        // Regular users/admins can only access resources they own or manage
        if (!user.getId().equals(resourceOwnerId) && 
                !user.getManagedUserIds().contains(resourceOwnerId)) {
            auditService.logCrossAccountAccess(user.getId(), resourceOwnerId);
            return AuthorizationResult.forbidden(
                "Cannot access resources belonging to other users");
        }

        return baseResult;
    }

    private String extractSessionId(HttpServletRequest request) {
        Cookie[] cookies = request.getCookies();
        if (cookies != null) {
            for (Cookie cookie : cookies) {
                if ("SESSION_ID".equals(cookie.getName())) {
                    return cookie.getValue();
                }
            }
        }
        return null;
    }

    private String getClientIp(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isEmpty()) {
            return xff.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private boolean isFromTrustedNetwork(String ip) {
        return ip.startsWith("10.0.") || ip.startsWith("192.168.1.");
    }
}

// Production controller with fine-grained authorization
@WebServlet("/api/admin/*")
public class ProductionAdminController extends HttpServlet {

    private static final Logger logger = Logger.getLogger(
            ProductionAdminController.class.getName());
    private final AuthorizationService authService;
    private final AuditService auditService;

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        response.setContentType("application/json");
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("Cache-Control", "no-store");

        String pathInfo = request.getPathInfo();
        String requestId = UUID.randomUUID().toString();

        try {
            if ("/users".equals(pathInfo)) {
                handleUserList(request, response, requestId);
            } else if ("/users/delete".equals(pathInfo)) {
                handleUserDelete(request, response, requestId);
            } else if ("/reports/export".equals(pathInfo)) {
                handleReportExport(request, response, requestId);
            } else if ("/system/config".equals(pathInfo)) {
                handleSystemConfig(request, response, requestId);
            } else {
                response.setStatus(HttpServletResponse.SC_NOT_FOUND);
            }
        } catch (Exception e) {
            logger.severe("Request " + requestId + " failed: " + e.getMessage());
            response.setStatus(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
            response.getWriter().write("{\"error\": \"Internal error\", " +
                    "\"requestId\": \"" + requestId + "\"}");
        }
    }

    private void handleUserDelete(HttpServletRequest request, 
            HttpServletResponse response, String requestId) throws IOException {

        // Require USER_DELETE permission
        AuthorizationResult authResult = authService.authorize(
                request, Permission.USER_DELETE);

        if (!authResult.isAuthorized()) {
            sendAuthError(response, authResult);
            return;
        }

        String targetUserId = request.getParameter("userId");
        if (targetUserId == null || !targetUserId.matches("^[a-zA-Z0-9-]+$")) {
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            response.getWriter().write("{\"error\": \"Invalid user ID format\"}");
            return;
        }

        User currentUser = authResult.getUser();

        // Prevent self-deletion
        if (currentUser.getId().equals(targetUserId)) {
            response.setStatus(HttpServletResponse.SC_FORBIDDEN);
            response.getWriter().write("{\"error\": \"Cannot delete your own account\"}");
            return;
        }

        // Log before action
        auditService.logAdminAction(
            currentUser.getId(),
            "USER_DELETE",
            targetUserId,
            requestId,
            Instant.now()
        );

        // Execute deletion
        userService.deleteUser(targetUserId);

        response.getWriter().write("{\"status\": \"deleted\", " +
                "\"requestId\": \"" + requestId + "\"}");
    }

    private void handleSystemConfig(HttpServletRequest request,
            HttpServletResponse response, String requestId) throws IOException {

        // Highest privilege level - SYSTEM_CONFIG
        AuthorizationResult authResult = authService.authorize(
                request, Permission.SYSTEM_CONFIG);

        if (!authResult.isAuthorized()) {
            sendAuthError(response, authResult);
            return;
        }

        // Additional MFA check for critical operations
        if (!verifyMfaToken(request)) {
            response.setStatus(HttpServletResponse.SC_FORBIDDEN);
            response.getWriter().write(
                "{\"error\": \"MFA verification required for this action\"}");
            return;
        }

        // Process system configuration...
    }

    private void sendAuthError(HttpServletResponse response, 
            AuthorizationResult result) throws IOException {
        if (result.isRateLimited()) {
            response.setStatus(429);
            response.setHeader("Retry-After", "60");
            response.getWriter().write("{\"error\": \"Too many requests\"}");
        } else if (!result.isAuthenticated()) {
            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
            response.getWriter().write("{\"error\": \"" + result.getMessage() + "\"}");
        } else {
            response.setStatus(HttpServletResponse.SC_FORBIDDEN);
            response.getWriter().write("{\"error\": \"" + result.getMessage() + "\"}");
        }
    }

    private void handleUserList(HttpServletRequest req, HttpServletResponse res, String rid) throws IOException { /* Implementation */ }
    private void handleReportExport(HttpServletRequest req, HttpServletResponse res, String rid) throws IOException { /* Implementation */ }
    private boolean verifyMfaToken(HttpServletRequest request) { return true; }
}
