**Key Security Controls**:
- **Server-side authorization**: Role checked from database on every request, not from client-provided data
- **Middleware chain**: Authentication verified before authorization, both before handler
- **Audit logging**: All admin actions logged with actor identity for forensics
- **Principle of least privilege**: Admin status never sent to client, only checked server-side

For production systems with complex authorization needs, you should implement Role-Based Access Control (RBAC) or Attribute-Based Access Control (ABAC) with centralized policy enforcement. Here's a production-ready pattern:

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"sync"
	"time"
)

// Permission represents a granular action
type Permission string

const (
	PermDeleteUser     Permission = "users:delete"
	PermEditUser       Permission = "users:edit"
	PermViewUsers      Permission = "users:view"
	PermManageRoles    Permission = "roles:manage"
	PermViewAdminPanel Permission = "admin:view"
	PermModerateContent Permission = "content:moderate"
)

// Role with associated permissions
type Role struct {
	Name        string
	Permissions []Permission
}

// Centralized RBAC policy store
type RBACPolicy struct {
	mu    sync.RWMutex
	roles map[string]Role
}

var policy = &RBACPolicy{
	roles: map[string]Role{
		"admin": {
			Name: "admin",
			Permissions: []Permission{
				PermDeleteUser, PermEditUser, PermViewUsers,
				PermManageRoles, PermViewAdminPanel, PermModerateContent,
			},
		},
		"moderator": {
			Name: "moderator",
			Permissions: []Permission{
				PermViewUsers, PermModerateContent,
			},
		},
		"user": {
			Name:        "user",
			Permissions: []Permission{},
		},
	},
}

// AuthContext contains authenticated user info - NEVER from client
type AuthContext struct {
	UserID    int
	Username  string
	Roles     []string
	SessionID string
	IPAddress string
}

type contextKey string

const authContextKey contextKey = "auth"

// Check if user has specific permission - SERVER-SIDE ONLY
func (p *RBACPolicy) HasPermission(roles []string, required Permission) bool {
	p.mu.RLock()
	defer p.mu.RUnlock()

	for _, roleName := range roles {
		if role, exists := p.roles[roleName]; exists {
			for _, perm := range role.Permissions {
				if perm == required {
					return true
				}
			}
		}
	}
	return false
}

// Middleware factory for permission-based authorization
func RequirePermission(perm Permission) func(http.HandlerFunc) http.HandlerFunc {
	return func(next http.HandlerFunc) http.HandlerFunc {
		return func(w http.ResponseWriter, r *http.Request) {
			auth := getAuthContext(r.Context())
			if auth == nil {
				logSecurityEvent("UNAUTH_ACCESS", 0, r.RemoteAddr, string(perm), "missing_auth")
				http.Error(w, `{"error": "unauthorized"}`, http.StatusUnauthorized)
				return
			}

			// CRITICAL: Server-side permission check from database-loaded roles
			if !policy.HasPermission(auth.Roles, perm) {
				logSecurityEvent("FORBIDDEN_ACCESS", auth.UserID, auth.IPAddress, string(perm), "insufficient_permissions")
				http.Error(w, `{"error": "forbidden"}`, http.StatusForbidden)
				return
			}

			logSecurityEvent("ACCESS_GRANTED", auth.UserID, auth.IPAddress, string(perm), "success")
			next(w, r)
		}
	}
}

// Authentication middleware - loads roles from database
func AuthMiddleware(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		token := extractToken(r)
		if token == "" {
			http.Error(w, `{"error": "missing token"}`, http.StatusUnauthorized)
			return
		}

		// Validate token and get user from database - NEVER trust client-provided roles
		userID, sessionID, err := validateToken(token)
		if err != nil {
			logSecurityEvent("INVALID_TOKEN", 0, r.RemoteAddr, "auth", err.Error())
			http.Error(w, `{"error": "invalid token"}`, http.StatusUnauthorized)
			return
		}

		// Load roles from database - authoritative source
		roles, err := loadUserRolesFromDB(userID)
		if err != nil {
			log.Printf("ERROR: Failed to load roles for user %d: %v", userID, err)
			http.Error(w, `{"error": "internal error"}`, http.StatusInternalServerError)
			return
		}

		auth := &AuthContext{
			UserID:    userID,
			Roles:     roles,
			SessionID: sessionID,
			IPAddress: r.RemoteAddr,
		}

		ctx := context.WithValue(r.Context(), authContextKey, auth)
		next(w, r.WithContext(ctx))
	}
}

// Security event logging for monitoring and alerting
func logSecurityEvent(eventType string, userID int, ipAddr, resource, details string) {
	event := map[string]interface{}{
		"timestamp":  time.Now().UTC().Format(time.RFC3339),
		"event_type": eventType,
		"user_id":    userID,
		"ip_address": ipAddr,
		"resource":   resource,
		"details":    details,
	}

	eventJSON, _ := json.Marshal(event)
	log.Printf("SECURITY_EVENT: %s", string(eventJSON))

	// In production: send to SIEM (Splunk, ELK, etc.)
	// sendToSIEM(event)
}

// Protected admin endpoint
func deleteUserHandler(w http.ResponseWriter, r *http.Request) {
	auth := getAuthContext(r.Context())

	var req struct {
		UserID int `json:"userId"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, `{"error": "invalid request"}`, http.StatusBadRequest)
		return
	}

	// Prevent self-deletion
	if req.UserID == auth.UserID {
		http.Error(w, `{"error": "cannot delete self"}`, http.StatusBadRequest)
		return
	}

	// Additional check: prevent deletion of other admins
	targetRoles, _ := loadUserRolesFromDB(req.UserID)
	for _, role := range targetRoles {
		if role == "admin" {
			logSecurityEvent("ADMIN_DELETE_ATTEMPT", auth.UserID, auth.IPAddress, 
				fmt.Sprintf("users:%d", req.UserID), "blocked_admin_deletion")
			http.Error(w, `{"error": "cannot delete admin users"}`, http.StatusForbidden)
			return
		}
	}

	// Audit trail
	logSecurityEvent("USER_DELETED", auth.UserID, auth.IPAddress,
		fmt.Sprintf("users:%d", req.UserID), "success")

	deleteUserFromDB(req.UserID)

	w.Header().Set("Content-Type", "application/json")
	w.Write([]byte(`{"status": "success"}`))
}

func getAuthContext(ctx context.Context) *AuthContext {
	if auth, ok := ctx.Value(authContextKey).(*AuthContext); ok {
		return auth
	}
	return nil
}

func main() {
	mux := http.NewServeMux()

	// Public endpoints
	mux.HandleFunc("/api/health", healthHandler)

	// Protected endpoints with granular permissions
	mux.HandleFunc("/api/users", AuthMiddleware(RequirePermission(PermViewUsers)(listUsersHandler)))
	mux.HandleFunc("/api/admin/delete-user", AuthMiddleware(RequirePermission(PermDeleteUser)(deleteUserHandler)))
	mux.HandleFunc("/api/admin/roles", AuthMiddleware(RequirePermission(PermManageRoles)(manageRolesHandler)))
	mux.HandleFunc("/api/moderate/content", AuthMiddleware(RequirePermission(PermModerateContent)(moderateHandler)))

	log.Println("Server starting on :8080")
	http.ListenAndServe(":8080", mux)
}

